#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>

int is_aligned(void *ptr, size_t alignment) {
    return ((uintptr_t)ptr % alignment) == 0;
}

validation.test_code:
#include <stdint.h>
int is_aligned(void *ptr, size_t alignment);

void test_is_aligned_true(void) {
    int *p = malloc(sizeof(int));
    TEST_ASSERT_EQUAL_INT(1, is_aligned(p, 4));
    free(p);
}

void test_is_aligned_false(void) {
    int *p = malloc(sizeof(int));
    int result = is_aligned(p, 64);
    /* malloc typically gives 16-byte alignment on x86-64, not 64 */
    TEST_ASSERT_NOT_NULL(p);
    free(p);
}

void test_aligned_alloc_64(void) {
    int *b = aligned_alloc(64, 64 * sizeof(int));
    TEST_ASSERT_NOT_NULL(b);
    TEST_ASSERT_EQUAL_INT(1, is_aligned(b, 4));
    TEST_ASSERT_EQUAL_INT(1, is_aligned(b, 16));
    TEST_ASSERT_EQUAL_INT(1, is_aligned(b, 64));
    free(b);
}

void test_aligned_alloc_store_data(void) {
    int *b = aligned_alloc(64, 64 * sizeof(int));
    TEST_ASSERT_NOT_NULL(b);
    for (int i = 0; i < 8; i++) b[i] = i * i;
    TEST_ASSERT_EQUAL_INT(0, b[0]);
    TEST_ASSERT_EQUAL_INT(1, b[1]);
    TEST_ASSERT_EQUAL_INT(49, b[7]);
    free(b);
}

int main(void) {
    RUN_TEST(test_is_aligned_true);
    RUN_TEST(test_is_aligned_false);
    RUN_TEST(test_aligned_alloc_64);
    RUN_TEST(test_aligned_alloc_store_data);
    TEST_SUMMARY();
    return _clings_failures > 0 ? 1 : 0;
}

